import React, { useState } from 'react';
import { View, Text, TouchableOpacity } from 'react-native';
import AsyncStorage from '@react-native-async-storage/async-storage';
import Biometrics from 'react-native-biometrics';

const Authenticate = () => {
  const [authenticated, setAuthenticated] = useState(false);

  const handleBiometricAuthentication = async () => {
    try {
      const biometricType = await Biometrics.getAvailableBiometrics();
      if (biometricType === 'FaceID') {
        const faceIdSuccessful = await Biometrics.authenticateWithFaceID();
        if (faceIdSuccessful) {
          setAuthenticated(true);
          AsyncStorage.setItem('authenticated', 'true');
        } else {
          console.log('Face ID authentication failed');
        }
      } else if (biometricType === 'TouchID') {
        const touchIdSuccessful = await Biometrics.authenticateWithTouchID();
        if (touchIdSuccessful) {
          setAuthenticated(true);
          AsyncStorage.setItem('authenticated', 'true');
        } else {
          console.log('Touch ID authentication failed');
        }
      } else {
        console.log('No biometric authentication available');
      }
    } catch (error) {
      console.log(error);
    }
  };

  const handlePasswordFallback = async () => {
    // Handle password fallback logic here
  };

  return (
    <View>
      {!authenticated && (
        <TouchableOpacity onPress={handleBiometricAuthentication}>
          <Text>Authenticate with Face ID or Touch ID</Text>
        </TouchableOpacity>
      )}
      {authenticated && (
        <TouchableOpacity onPress={handlePasswordFallback}>
          <Text>Authenticate with password</Text>
        </TouchableOpacity>
      )}
    </View>
  );
};